let n;
let nums = [];
let target;
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else if (i <= n) {
        nums.push(parseInt(line));
    } else if (i === n + 1) {
        target = parseInt(line);
        const solution = new Solution();
        const result = solution.twoSum(nums, target);
