#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int target; cin >> target;
    unordered_map<int, int> indices;
    for(int i = 0; i < n; i++){
        int complement = target - nums[i];
        if(indices.find(complement) != indices.end()){
            cout << indices[complement] << " " << i;
            return 0;
        }
        indices[nums[i]] = i;
    }
}
